    {"offset": {"line": 1285, "column": 0}, "map": {"version":3,"sources":["file:///Users/badalkumar/Desktop/kk-padho-india/src/components/Hero.tsx"],"sourcesContent":["\"use client\";\n\nimport { useRef, useState, useEffect } from \"react\";\n\ninterface Video {\n  id: number;\n  src: string;\n  title: string;\n  mainHeading: string;\n  subHeading: string;\n}\n\nexport default function Hero() {\n  const [activeVideo, setActiveVideo] = useState<number>(0);\n  const [isAutoPlaying, setIsAutoPlaying] = useState<boolean>(true);\n  const videoRefs = useRef<(HTMLVideoElement | null)[]>([]);\n\n  const videos: Video[] = [\n    {\n      id: 1,\n      src: \"/Videos/study.mp4\",\n      title: \"Smart Study Techniques\",\n      mainHeading: \"Master Smart Study Techniques\",\n      subHeading: \"Learn How Top Students Study\"\n    },\n    {\n      id: 2,\n      src: \"/Videos/study1.mp4\",\n      title: \"Smart Study Techniques\",\n      mainHeading: \"Master Smart Study Techniques\",\n      subHeading: \"Learn How Top Students Study\"\n    },\n    {\n      id: 3,\n      src: \"/Videos/study2.mp4\",\n      title: \"Exam Preparation Guide\",\n      mainHeading: \"Ace Your Exams With Confidence\",\n      subHeading: \"Proven Exam Preparation Strategies\"\n    },\n    {\n      id: 4,\n      src: \"/Videos/study3.mp4\",\n      title: \"Student Success Stories\",\n      mainHeading: \"Inspiring Student Success Stories\",\n      subHeading: \"Real Stories, Real Achievements\"\n    },\n    {\n      id: 5,\n      src: \"/Videos/study4.mp4\",\n      title: \"Effective Learning Methods\",\n      mainHeading: \"Innovative Learning Methods\",\n      subHeading: \"Make Learning Fun & Effective\"\n    }\n  ];\n\n  // Auto-play carousel every 3 seconds\n  useEffect(() => {\n    let interval: NodeJS.Timeout;\n    if (isAutoPlaying) {\n      interval = setInterval(() => {\n        setActiveVideo((prev: number) => (prev + 1) % videos.length);\n      }, 3000);\n    }\n    return () => clearInterval(interval);\n  }, [isAutoPlaying, videos.length]);\n\n  // Play/pause videos based on active state\n  useEffect(() => {\n    videoRefs.current.forEach((video: HTMLVideoElement | null) => {\n      if (video) {\n        video.pause();\n      }\n    });\n\n    const activeVideoElement = videoRefs.current[activeVideo];\n    if (activeVideoElement) {\n      activeVideoElement.play().catch((error: Error) => {\n        console.log(\"Video play failed:\", error);\n      });\n    }\n  }, [activeVideo]);\n\n  const handleDotClick = (index: number) => {\n    setActiveVideo(index);\n    setIsAutoPlaying(false);\n    setTimeout(() => setIsAutoPlaying(true), 10000);\n  };\n\n  return (\n    <section className=\"relative w-full min-h-screen bg-black overflow-hidden\">\n      \n      {/* Main Background Video */}\n      <div className=\"absolute inset-0 w-full h-full\">\n        {videos.map((video: Video, index: number) => (\n          <video\n            key={video.id}\n            ref={(el: HTMLVideoElement | null) => {\n              if (el) {\n                videoRefs.current[index] = el;\n              }\n            }}\n            className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-1000 ${\n              activeVideo === index ? \"opacity-100\" : \"opacity-0\"\n            }`}\n            src={video.src}\n            muted\n            loop\n            playsInline\n            preload=\"auto\"\n          />\n        ))}\n        <div className=\"absolute inset-0 bg-gradient-to-r from-black/70 via-black/50 to-black/70\"></div>\n      </div>\n\n      {/* Content Overlay */}\n      <div className=\"relative z-10 flex flex-col items-center justify-between min-h-screen px-4 py-6 sm:py-12\">\n        \n        {/* KK PADHO INDIA */}\n        <div className=\"text-center w-full pt-2 sm:pt-4\">\n          <h1 className=\"text-xl sm:text-2xl md:text-3xl lg:text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-green-400 to-blue-500\">\n            KK PADHO INDIA\n          </h1>\n          <div className=\"h-0.5 w-12 sm:w-16 bg-gradient-to-r from-green-400 to-blue-500 mx-auto mt-1\"></div>\n        </div>\n\n        {/* Main Content */}\n        <div className=\"w-full max-w-5xl mx-auto text-center px-2 sm:px-4\">\n          \n          {/* Dynamic Text */}\n          <div className=\"mb-6 sm:mb-8 md:mb-12 animate-fadeIn\">\n            <h2 className=\"text-xl sm:text-2xl md:text-4xl lg:text-5xl xl:text-6xl font-bold text-white mb-2 sm:mb-4 drop-shadow-lg leading-tight\">\n              {videos[activeVideo].mainHeading}\n            </h2>\n            \n            <h3 className=\"text-base sm:text-xl md:text-2xl lg:text-3xl text-blue-400 drop-shadow-lg\">\n              {videos[activeVideo].subHeading}\n            </h3>\n          </div>\n\n          {/* Dot Carousel */}\n          <div className=\"flex items-center justify-center gap-2 sm:gap-3 mt-4 sm:mt-6 md:mt-8\">\n            {videos.map((_: Video, index: number) => (\n              <button\n                key={index}\n                onClick={() => handleDotClick(index)}\n                className=\"group relative\"\n              >\n                <div\n                  className={`h-2 sm:h-3 rounded-full transition-all duration-300 ${\n                    activeVideo === index \n                      ? \"w-6 sm:w-8 md:w-10 bg-blue-400 shadow-lg shadow-blue-500/50\" \n                      : \"w-2 sm:w-3 bg-white/70 hover:bg-white\"\n                  }`}\n                />\n                <span className=\"hidden sm:block absolute -top-8 left-1/2 transform -translate-x-1/2 bg-gray-900/90 text-white text-xs py-1 px-2 rounded opacity-0 group-hover:opacity-100 transition-opacity duration-300 whitespace-nowrap backdrop-blur-sm\">\n                  {videos[index].title}\n                </span>\n              </button>\n            ))}\n          </div>\n\n          {/* Current Video Title */}\n          <div className=\"mt-3 sm:mt-4 md:mt-6\">\n            <p className=\"text-xs sm:text-sm md:text-base text-blue-400 font-semibold drop-shadow-lg\">\n              Currently: {videos[activeVideo].title}\n            </p>\n          </div>\n        </div>\n\n        {/* CTA Button */}\n        <div className=\"text-center mb-2 sm:mb-4 md:mb-8\">\n          <button className=\"group relative px-4 sm:px-6 md:px-8 py-2 sm:py-3 md:py-4 bg-gradient-to-r from-green-600 to-blue-600 hover:from-green-700 hover:to-blue-700 text-white text-sm sm:text-base md:text-lg font-semibold rounded-full transition-all duration-300 transform hover:scale-105 shadow-xl hover:shadow-blue-500/40 overflow-hidden backdrop-blur-sm\">\n            <span className=\"relative z-10\">Explore {videos[activeVideo].title}</span>\n            <div className=\"absolute inset-0 bg-white/20 transform -translate-x-full group-hover:translate-x-0 transition-transform duration-300\"></div>\n          </button>\n        </div>\n      </div>\n\n      <style jsx>{`\n        @keyframes fadeIn {\n          from {\n            opacity: 0;\n            transform: translateY(20px);\n          }\n          to {\n            opacity: 1;\n            transform: translateY(0);\n          }\n        }\n        \n        .animate-fadeIn {\n          animation: fadeIn 0.5s ease-out;\n        }\n\n        /* Mobile specific styles */\n        @media (max-width: 640px) {\n          .animate-fadeIn {\n            animation: fadeIn 0.3s ease-out;\n          }\n        }\n      `}</style>\n    </section>\n  );\n}"],"names":[],"mappings":";;;;;;AAEA;;;AAFA;;;AAYe,SAAS;;IACtB,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,yKAAQ,EAAS;IACvD,MAAM,CAAC,eAAe,iBAAiB,GAAG,IAAA,yKAAQ,EAAU;IAC5D,MAAM,YAAY,IAAA,uKAAM,EAA8B,EAAE;IAExD,MAAM,SAAkB;QACtB;YACE,IAAI;YACJ,KAAK;YACL,OAAO;YACP,aAAa;YACb,YAAY;QACd;QACA;YACE,IAAI;YACJ,KAAK;YACL,OAAO;YACP,aAAa;YACb,YAAY;QACd;QACA;YACE,IAAI;YACJ,KAAK;YACL,OAAO;YACP,aAAa;YACb,YAAY;QACd;QACA;YACE,IAAI;YACJ,KAAK;YACL,OAAO;YACP,aAAa;YACb,YAAY;QACd;QACA;YACE,IAAI;YACJ,KAAK;YACL,OAAO;YACP,aAAa;YACb,YAAY;QACd;KACD;IAED,qCAAqC;IACrC,IAAA,0KAAS;0BAAC;YACR,IAAI;YACJ,IAAI,eAAe;gBACjB,WAAW;sCAAY;wBACrB;8CAAe,CAAC,OAAiB,CAAC,OAAO,CAAC,IAAI,OAAO,MAAM;;oBAC7D;qCAAG;YACL;YACA;kCAAO,IAAM,cAAc;;QAC7B;yBAAG;QAAC;QAAe,OAAO,MAAM;KAAC;IAEjC,0CAA0C;IAC1C,IAAA,0KAAS;0BAAC;YACR,UAAU,OAAO,CAAC,OAAO;kCAAC,CAAC;oBACzB,IAAI,OAAO;wBACT,MAAM,KAAK;oBACb;gBACF;;YAEA,MAAM,qBAAqB,UAAU,OAAO,CAAC,YAAY;YACzD,IAAI,oBAAoB;gBACtB,mBAAmB,IAAI,GAAG,KAAK;sCAAC,CAAC;wBAC/B,QAAQ,GAAG,CAAC,sBAAsB;oBACpC;;YACF;QACF;yBAAG;QAAC;KAAY;IAEhB,MAAM,iBAAiB,CAAC;QACtB,eAAe;QACf,iBAAiB;QACjB,WAAW,IAAM,iBAAiB,OAAO;IAC3C;IAEA,qBACE,6LAAC;kDAAkB;;0BAGjB,6LAAC;0DAAc;;oBACZ,OAAO,GAAG,CAAC,CAAC,OAAc,sBACzB,6LAAC;4BAEC,KAAK,CAAC;gCACJ,IAAI,IAAI;oCACN,UAAU,OAAO,CAAC,MAAM,GAAG;gCAC7B;4BACF;4BAIA,KAAK,MAAM,GAAG;4BACd,KAAK;4BACL,IAAI;4BACJ,WAAW;4BACX,SAAQ;sEAPG,CAAC,6EAA6E,EACvF,gBAAgB,QAAQ,gBAAgB,aACxC;2BARG,MAAM,EAAE;;;;;kCAgBjB,6LAAC;kEAAc;;;;;;;;;;;;0BAIjB,6LAAC;0DAAc;;kCAGb,6LAAC;kEAAc;;0CACb,6LAAC;0EAAa;0CAAkI;;;;;;0CAGhJ,6LAAC;0EAAc;;;;;;;;;;;;kCAIjB,6LAAC;kEAAc;;0CAGb,6LAAC;0EAAc;;kDACb,6LAAC;kFAAa;kDACX,MAAM,CAAC,YAAY,CAAC,WAAW;;;;;;kDAGlC,6LAAC;kFAAa;kDACX,MAAM,CAAC,YAAY,CAAC,UAAU;;;;;;;;;;;;0CAKnC,6LAAC;0EAAc;0CACZ,OAAO,GAAG,CAAC,CAAC,GAAU,sBACrB,6LAAC;wCAEC,SAAS,IAAM,eAAe;kFACpB;;0DAEV,6LAAC;0FACY,CAAC,oDAAoD,EAC9D,gBAAgB,QACZ,gEACA,yCACJ;;;;;;0DAEJ,6LAAC;0FAAe;0DACb,MAAM,CAAC,MAAM,CAAC,KAAK;;;;;;;uCAZjB;;;;;;;;;;0CAmBX,6LAAC;0EAAc;0CACb,cAAA,6LAAC;8EAAY;;wCAA6E;wCAC5E,MAAM,CAAC,YAAY,CAAC,KAAK;;;;;;;;;;;;;;;;;;kCAM3C,6LAAC;kEAAc;kCACb,cAAA,6LAAC;sEAAiB;;8CAChB,6LAAC;8EAAe;;wCAAgB;wCAAS,MAAM,CAAC,YAAY,CAAC,KAAK;;;;;;;8CAClE,6LAAC;8EAAc;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;AA8B3B;GA/LwB;KAAA"}},
    {"offset": {"line": 1596, "column": 0}, "map": {"version":3,"sources":["file:///Users/badalkumar/Desktop/kk-padho-india/src/components/Scholarship/HeroSection.tsx"],"sourcesContent":["\"use client\";\n\nimport React from 'react';\n\nexport default function ScholarshipHero() {\n  return (\n    <section className=\"relative w-full bg-gradient-to-br from-yellow-200 via-purple-50 to-pink-200 py-20 px-4 sm:px-6 lg:px-8 overflow-hidden\">\n      \n      {/* Animated Background - Soft Colors */}\n      <div className=\"absolute inset-0 overflow-hidden\">\n        <div className=\"absolute -top-40 -right-40 w-80 h-80 bg-blue-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob\"></div>\n        <div className=\"absolute -bottom-40 -left-40 w-80 h-80 bg-purple-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000\"></div>\n        <div className=\"absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-80 h-80 bg-pink-300 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-4000\"></div>\n      </div>\n\n      <div className=\"relative max-w-7xl mx-auto text-center\">\n        {/* Badge */}\n        <div className=\"inline-flex items-center bg-white/60 backdrop-blur-sm rounded-full px-4 py-2 mb-8 border border-blue-200 shadow-sm\">\n          <span className=\"w-2 h-2 bg-blue-500 rounded-full animate-pulse mr-2\"></span>\n          <span className=\"text-blue-700 text-sm font-medium tracking-wider\">EDUCATION FOR ALL</span>\n        </div>\n\n        {/* Main Heading */}\n        <h3 className=\"text-4xl md:text-6xl lg:text-6xl font-bold mb-6\">\n          <span className=\"bg-gradient-to-r from-blue-700 to-purple-700 bg-clip-text text-transparent\">\n            PADHO INDIA SCHOLARSHIP\n          </span>\n        </h3>\n        \n        {/* Main Message */}\n        <p className=\"text-2xl md:text-3xl text-purple-600 font-semibold mb-4\">\n          Millions Candidates Will Become Crorepatis.\n        </p>\n        \n        {/* Stats Box */}\n        <div className=\"bg-white/70 backdrop-blur-sm rounded-2xl p-6 mb-6 border border-blue-200 max-w-3xl mx-auto shadow-md\">\n          <p className=\"text-xl md:text-2xl text-gray-800 mb-3\">\n            Over 10 Lakhs Students will get Scholarship...\n          </p>\n          <p className=\"text-lg md:text-xl text-purple-600\">\n            And Millions of Students will make career by Higher study.\n          </p>\n        </div>\n\n        {/* Feature Chips */}\n        <div className=\"flex flex-wrap justify-center gap-3 mb-8\">\n          <span className=\"bg-blue-50 border border-blue-200 rounded-full px-4 py-2 text-blue-700 text-sm shadow-sm\">\n            🏆 Top Scholarships\n          </span>\n          <span className=\"bg-purple-50 border border-purple-200 rounded-full px-4 py-2 text-purple-700 text-sm shadow-sm\">\n            📚 Free Education\n          </span>\n          <span className=\"bg-pink-50 border border-pink-200 rounded-full px-4 py-2 text-pink-700 text-sm shadow-sm\">\n            🎯 Career Guidance\n          </span>\n        </div>\n\n        {/* Decorative Icons */}\n        <div className=\"mt-8 flex justify-center gap-4\">\n          <div className=\"w-16 h-16 bg-gradient-to-br from-blue-400 to-purple-400 rounded-full flex items-center justify-center shadow-md animate-float\">\n            <span className=\"text-3xl\">🏆</span>\n          </div>\n          <div className=\"w-16 h-16 bg-gradient-to-br from-purple-400 to-pink-400 rounded-full flex items-center justify-center shadow-md animate-float animation-delay-1000\">\n            <span className=\"text-3xl\">⭐</span>\n          </div>\n          <div className=\"w-16 h-16 bg-gradient-to-br from-pink-400 to-orange-400 rounded-full flex items-center justify-center shadow-md animate-float animation-delay-2000\">\n            <span className=\"text-3xl\">🎓</span>\n          </div>\n        </div>\n\n        {/* CTA Button */}\n        <div className=\"mt-10\">\n          <button className=\"bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-3 rounded-full font-bold text-lg hover:from-blue-700 hover:to-purple-700 transform hover:scale-105 transition-all duration-300 shadow-md\">\n            Apply for Scholarship\n          </button>\n          <p className=\"text-gray-600 text-sm mt-3\">No application fee • Open for all students</p>\n        </div>\n      </div>\n\n      <style jsx>{`\n        @keyframes blob {\n          0% { transform: translate(0px, 0px) scale(1); }\n          33% { transform: translate(30px, -50px) scale(1.1); }\n          66% { transform: translate(-20px, 20px) scale(0.9); }\n          100% { transform: translate(0px, 0px) scale(1); }\n        }\n        .animate-blob { animation: blob 7s infinite; }\n        \n        @keyframes float {\n          0%, 100% { transform: translateY(0px); }\n          50% { transform: translateY(-10px); }\n        }\n        .animate-float { animation: float 3s ease-in-out infinite; }\n        \n        .animation-delay-1000 { animation-delay: 1s; }\n        .animation-delay-2000 { animation-delay: 2s; }\n        .animation-delay-4000 { animation-delay: 4s; }\n      `}</style>\n    </section>\n  );\n}"],"names":[],"mappings":";;;;;;AAAA;;;AAIe,SAAS;IACtB,qBACE,6LAAC;kDAAkB;;0BAGjB,6LAAC;0DAAc;;kCACb,6LAAC;kEAAc;;;;;;kCACf,6LAAC;kEAAc;;;;;;kCACf,6LAAC;kEAAc;;;;;;;;;;;;0BAGjB,6LAAC;0DAAc;;kCAEb,6LAAC;kEAAc;;0CACb,6LAAC;0EAAe;;;;;;0CAChB,6LAAC;0EAAe;0CAAmD;;;;;;;;;;;;kCAIrE,6LAAC;kEAAa;kCACZ,cAAA,6LAAC;sEAAe;sCAA6E;;;;;;;;;;;kCAM/F,6LAAC;kEAAY;kCAA0D;;;;;;kCAKvE,6LAAC;kEAAc;;0CACb,6LAAC;0EAAY;0CAAyC;;;;;;0CAGtD,6LAAC;0EAAY;0CAAqC;;;;;;;;;;;;kCAMpD,6LAAC;kEAAc;;0CACb,6LAAC;0EAAe;0CAA2F;;;;;;0CAG3G,6LAAC;0EAAe;0CAAiG;;;;;;0CAGjH,6LAAC;0EAAe;0CAA2F;;;;;;;;;;;;kCAM7G,6LAAC;kEAAc;;0CACb,6LAAC;0EAAc;0CACb,cAAA,6LAAC;8EAAe;8CAAW;;;;;;;;;;;0CAE7B,6LAAC;0EAAc;0CACb,cAAA,6LAAC;8EAAe;8CAAW;;;;;;;;;;;0CAE7B,6LAAC;0EAAc;0CACb,cAAA,6LAAC;8EAAe;8CAAW;;;;;;;;;;;;;;;;;kCAK/B,6LAAC;kEAAc;;0CACb,6LAAC;0EAAiB;0CAA2M;;;;;;0CAG7N,6LAAC;0EAAY;0CAA6B;;;;;;;;;;;;;;;;;;;;;;;;;;;;AAyBpD;KAhGwB"}},
    {"offset": {"line": 1853, "column": 0}, "map": {"version":3,"sources":["file:///Users/badalkumar/Desktop/kk-padho-india/src/components/Scholarship/ServicesGrid.tsx"],"sourcesContent":["\"use client\";\n\nimport React from 'react';\n\ninterface Service {\n  title: string;\n  icon: string;\n  color: string;\n}\n\ninterface ScholarshipFeature {\n  title: string;\n  description: string;\n  icon: string;\n  color: string;\n  buttonText?: string;\n}\n\nexport default function ServicesGrid() {\n  const services: Service[] = [\n    { title: \"Scholarship Details\", icon: \"🎓\", color: \"blue\" },\n    { title: \"Free Tuitions (5 to 12)\", icon: \"📚\", color: \"green\" },\n    { title: \"Students Registration\", icon: \"📝\", color: \"purple\" },\n    { title: \"Scholarship System\", icon: \"💰\", color: \"yellow\" },\n    { title: \"Free IT Training\", icon: \"💻\", color: \"indigo\" },\n    { title: \"School Benefits\", icon: \"🏫\", color: \"red\" },\n    { title: \"Get Membership Card\", icon: \"💳\", color: \"pink\" },\n    { title: \"Free Medical Treatment\", icon: \"🏥\", color: \"teal\" },\n    { title: \"Legal Support\", icon: \"⚖️\", color: \"orange\" },\n    { title: \"Job Vacancy\", icon: \"💼\", color: \"cyan\" },\n    { title: \"Free Spoken English\", icon: \"🗣️\", color: \"emerald\" },\n    { title: \"Up to 70% discount for medicines\", icon: \"💊\", color: \"rose\" }\n  ];\n\n  const scholarshipFeatures: ScholarshipFeature[] = [\n    {\n      title: \"Free Scholarship\",\n      description: \"Merit-based and need-based scholarships for deserving students. Covers tuition fees, study materials, and additional academic support.\",\n      icon: \"🎓\",\n      color: \"gold\",\n      buttonText: \"Apply Now\"\n    },\n    {\n      title: \"Scholarship System\",\n      description: \"Comprehensive scholarship management system with easy application, tracking, and renewal process. Get real-time updates on your application status.\",\n      icon: \"⚙️\",\n      color: \"blue\",\n      buttonText: \"Learn More\"\n    },\n    {\n      title: \"Get Membership Card\",\n      description: \"Exclusive membership card providing access to all facilities, discounts, and priority support across all our programs and services.\",\n      icon: \"💳\",\n      color: \"purple\",\n      buttonText: \"Get Card\"\n    },\n    {\n      title: \"Career Counseling\",\n      description: \"Professional career guidance, aptitude testing, and personalized roadmaps for your dream career path.\",\n      icon: \"🤝\",\n      color: \"amber\",\n      buttonText: \"Book Session\"\n    },\n    {\n      title: \"50% Discount on QAR\",\n      description: \"Special discount on Quality Assessment Reports (QAR) for all scholarship holders and members.\",\n      icon: \"🚗\",\n      color: \"green\",\n      buttonText: \"Claim Discount\"\n    },\n    {\n      title: \"State Level Top School List\",\n      description: \"Recognition and ranking of top-performing schools at state level. Get insights into academic excellence benchmarks.\",\n      icon: \"🏆\",\n      color: \"orange\",\n      buttonText: \"View List\"\n    },\n    {\n      title: \"National Level Top School\",\n      description: \"National recognition for outstanding educational institutions. Comprehensive ranking based on multiple parameters.\",\n      icon: \"⭐\",\n      color: \"red\",\n      buttonText: \"Explore\"\n    }\n  ];\n\n  const getColorClasses = (color: string) => {\n    const colors: Record<string, { bg: string, text: string, hover: string, border: string, gradient?: string }> = {\n      blue: { bg: \"bg-blue-50/90 backdrop-blur-sm\", text: \"text-blue-700\", hover: \"hover:bg-blue-600 hover:text-white\", border: \"border-blue-200\" },\n      green: { bg: \"bg-green-50/90 backdrop-blur-sm\", text: \"text-green-700\", hover: \"hover:bg-green-600 hover:text-white\", border: \"border-green-200\" },\n      purple: { bg: \"bg-purple-50/90 backdrop-blur-sm\", text: \"text-purple-700\", hover: \"hover:bg-purple-600 hover:text-white\", border: \"border-purple-200\" },\n      yellow: { bg: \"bg-yellow-50/90 backdrop-blur-sm\", text: \"text-yellow-700\", hover: \"hover:bg-yellow-600 hover:text-white\", border: \"border-yellow-200\" },\n      indigo: { bg: \"bg-indigo-50/90 backdrop-blur-sm\", text: \"text-indigo-700\", hover: \"hover:bg-indigo-600 hover:text-white\", border: \"border-indigo-200\" },\n      red: { bg: \"bg-red-50/90 backdrop-blur-sm\", text: \"text-red-700\", hover: \"hover:bg-red-600 hover:text-white\", border: \"border-red-200\" },\n      pink: { bg: \"bg-pink-50/90 backdrop-blur-sm\", text: \"text-pink-700\", hover: \"hover:bg-pink-600 hover:text-white\", border: \"border-pink-200\" },\n      teal: { bg: \"bg-teal-50/90 backdrop-blur-sm\", text: \"text-teal-700\", hover: \"hover:bg-teal-600 hover:text-white\", border: \"border-teal-200\" },\n      orange: { bg: \"bg-orange-50/90 backdrop-blur-sm\", text: \"text-orange-700\", hover: \"hover:bg-orange-600 hover:text-white\", border: \"border-orange-200\" },\n      cyan: { bg: \"bg-cyan-50/90 backdrop-blur-sm\", text: \"text-cyan-700\", hover: \"hover:bg-cyan-600 hover:text-white\", border: \"border-cyan-200\" },\n      emerald: { bg: \"bg-emerald-50/90 backdrop-blur-sm\", text: \"text-emerald-700\", hover: \"hover:bg-emerald-600 hover:text-white\", border: \"border-emerald-200\" },\n      violet: { bg: \"bg-violet-50/90 backdrop-blur-sm\", text: \"text-violet-700\", hover: \"hover:bg-violet-600 hover:text-white\", border: \"border-violet-200\" },\n      rose: { bg: \"bg-rose-50/90 backdrop-blur-sm\", text: \"text-rose-700\", hover: \"hover:bg-rose-600 hover:text-white\", border: \"border-rose-200\" },\n      amber: { bg: \"bg-amber-50/90 backdrop-blur-sm\", text: \"text-amber-700\", hover: \"hover:bg-amber-600 hover:text-white\", border: \"border-amber-200\" },\n      lime: { bg: \"bg-lime-50/90 backdrop-blur-sm\", text: \"text-lime-700\", hover: \"hover:bg-lime-600 hover:text-white\", border: \"border-lime-200\" },\n      fuchsia: { bg: \"bg-fuchsia-50/90 backdrop-blur-sm\", text: \"text-fuchsia-700\", hover: \"hover:bg-fuchsia-600 hover:text-white\", border: \"border-fuchsia-200\" },\n      sky: { bg: \"bg-sky-50/90 backdrop-blur-sm\", text: \"text-sky-700\", hover: \"hover:bg-sky-600 hover:text-white\", border: \"border-sky-200\" },\n      gold: { bg: \"bg-amber-50/90 backdrop-blur-sm\", text: \"text-amber-700\", hover: \"hover:bg-amber-600 hover:text-white\", border: \"border-amber-200\", gradient: \"from-amber-400 to-yellow-500\" }\n    };\n    return colors[color] || colors.blue;\n  };\n\n  return (\n    <>\n      {/* Facilities Section */}\n      <section className=\"relative w-full py-20 px-4 sm:px-6 lg:px-8 overflow-hidden\">\n        {/* Background Image with Overlay */}\n        <div className=\"absolute inset-0 z-0\">\n          <img \n            src=\"/images/study.png\" \n            alt=\"Students studying\" \n            className=\"w-full h-full object-cover\"\n          />\n          {/* Decorative Pattern Overlay */}\n          <div className=\"absolute inset-0 opacity-10\">\n            <div className=\"absolute inset-0\" style={{\n              backgroundImage: `url(\"data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.4'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E\")`,\n              backgroundSize: '60px 60px'\n            }}></div>\n          </div>\n        </div>\n\n        <div className=\"relative z-10 max-w-7xl mx-auto\">\n          {/* Header with Glass Effect */}\n          <div className=\"text-center mb-12\">\n            <div className=\"inline-block bg-black/100 backdrop-blur-md rounded-full px-6 py-2 mb-4 border border-white/20\">\n              <span className=\"text-white/90 text-sm font-medium tracking-wider\">⚡ OUR FACILITIES ⚡</span>\n            </div>\n            \n            <h2 className=\"text-4xl md:text-5xl font-bold mb-4\">\n              <span className=\"bg-gradient-to-r from-yellow-300 via-orange-300 to-pink-300 bg-clip-text text-transparent\">\n                Discover Our Facilities\n              </span>\n            </h2>\n            \n            <div className=\"w-24 h-1 bg-gradient-to-r from-yellow-400 to-pink-400 mx-auto mb-6\"></div>\n            \n            <p className=\"text-lg md:text-xl text-white/90 max-w-3xl mx-auto leading-relaxed\">\n              Experience unparalleled educational support with expert mentorship, \n              exclusive scholarships, and personalized coaching designed for your success.\n            </p>\n          </div>\n\n          {/* Services Grid */}\n          <div className=\"grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5\">\n            {services.map((service, index) => {\n              const colors = getColorClasses(service.color);\n              return (\n                <div\n                  key={index}\n                  className={`group ${colors.bg} ${colors.border} border-2 rounded-xl p-5 \n                            hover:shadow-2xl transition-all duration-500 cursor-pointer\n                            transform hover:-translate-y-2 hover:scale-105\n                            backdrop-blur-sm ${colors.hover} relative overflow-hidden`}\n                >\n                  {/* Decorative Corner */}\n                  <div className=\"absolute top-0 right-0 w-16 h-16 bg-gradient-to-br from-white/20 to-transparent rounded-bl-3xl opacity-0 group-hover:opacity-100 transition-opacity duration-500\"></div>\n                  \n                  {/* Content */}\n                  <div className=\"flex flex-col items-center text-center relative z-10\">\n                    <div className={`w-16 h-16 ${colors.text} bg-white/50 backdrop-blur-sm rounded-2xl flex items-center justify-center mb-3 group-hover:scale-110 transition-transform duration-300 group-hover:rotate-3`}>\n                      <span className=\"text-4xl\">{service.icon}</span>\n                    </div>\n                    \n                    <span className={`font-semibold text-base ${colors.text} group-hover:text-white transition-colors duration-300`}>\n                      {service.title}\n                    </span>\n                    \n                    {/* Hover Indicator */}\n                    <div className=\"mt-3 w-8 h-0.5 bg-current opacity-0 group-hover:opacity-100 transition-all duration-300 group-hover:w-12\"></div>\n                  </div>\n\n                  {/* Shine Effect */}\n                  <div className=\"absolute inset-0 -translate-x-full group-hover:translate-x-full transition-transform duration-700 bg-gradient-to-r from-transparent via-white/20 to-transparent\"></div>\n                </div>\n              );\n            })}\n          </div>\n\n          {/* Bottom Decoration */}\n          <div className=\"mt-12 text-center\">\n            <div className=\"inline-flex items-center gap-3 bg-black/100 backdrop-blur-md rounded-full px-6 py-3 border border-white/20\">\n              <span className=\"w-2 h-2 bg-green-400 rounded-full animate-pulse\"></span>\n              <span className=\"text-white/90 text-sm\">12+ Facilities Available</span>\n              <span className=\"w-2 h-2 bg-yellow-400 rounded-full animate-pulse\"></span>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Scholarship Section */}\n      <section className=\"relative w-full py-20 px-4 sm:px-6 lg:px-8 overflow-hidden bg-gradient-to-br from-gray-900 via-gray-800 to-gray-900\">\n        {/* Background Pattern */}\n        <div className=\"absolute inset-0 opacity-10\">\n          <div className=\"absolute inset-0\" style={{\n            backgroundImage: `url(\"data:image/svg+xml,%3Csvg width='80' height='80' viewBox='0 0 80 80' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.4'%3E%3Cpath d='M40 20 L44 28 L52 30 L46 36 L48 44 L40 40 L32 44 L34 36 L28 30 L36 28 Z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E\")`,\n            backgroundSize: '80px 80px'\n          }}></div>\n        </div>\n\n        <div className=\"relative z-10 max-w-7xl mx-auto\">\n          {/* Section Header */}\n          <div className=\"text-center mb-12\">\n            <div className=\"inline-block bg-white/10 backdrop-blur-md rounded-full px-6 py-2 mb-4 border border-white/20\">\n              <span className=\"text-yellow-400 text-sm font-medium tracking-wider\">🏆 SCHOLARSHIP PROGRAMS 🏆</span>\n            </div>\n            \n            <h2 className=\"text-4xl md:text-5xl font-bold mb-4\">\n              <span className=\"bg-gradient-to-r from-yellow-400 via-orange-400 to-red-400 bg-clip-text text-transparent\">\n                Unlock Your Potential\n              </span>\n            </h2>\n            \n            <div className=\"w-24 h-1 bg-gradient-to-r from-yellow-400 to-red-400 mx-auto mb-6\"></div>\n            \n            <p className=\"text-lg md:text-xl text-gray-300 max-w-3xl mx-auto leading-relaxed\">\n              Access world-class scholarship opportunities, exclusive benefits, and recognition programs \n              designed to support your educational journey and career growth.\n            </p>\n          </div>\n\n          {/* Scholarship Features Grid */}\n          <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-16\">\n            {scholarshipFeatures.map((feature, index) => {\n              const colors = getColorClasses(feature.color);\n              return (\n                <div\n                  key={index}\n                  className={`group relative bg-white/5 backdrop-blur-sm rounded-2xl p-6 \n                            border border-white/10 hover:border-${feature.color}-400/50\n                            transition-all duration-500 hover:transform hover:-translate-y-2\n                            hover:shadow-2xl hover:shadow-${feature.color}-500/10 overflow-hidden`}\n                >\n                  {/* Glow Effect */}\n                  <div className={`absolute inset-0 bg-gradient-to-br from-${feature.color}-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500`}></div>\n                  \n                  {/* Icon */}\n                  <div className={`w-16 h-16 rounded-2xl bg-gradient-to-br from-${feature.color}-400/20 to-${feature.color}-600/20 \n                                flex items-center justify-center mb-4 group-hover:scale-110 transition-transform duration-300`}>\n                    <span className=\"text-4xl\">{feature.icon}</span>\n                  </div>\n                  \n                  {/* Content */}\n                  <h3 className={`text-xl font-bold mb-3 group-hover:text-${feature.color}-400 transition-colors duration-300`}>\n                    {feature.title}\n                  </h3>\n                  \n                  <p className=\"text-gray-400 mb-5 leading-relaxed\">\n                    {feature.description}\n                  </p>\n                  \n                  {/* Button */}\n                  {feature.buttonText && (\n                    <button className={`inline-flex items-center gap-2 px-4 py-2 rounded-lg \n                                      bg-gradient-to-r from-${feature.color}-500 to-${feature.color}-600\n                                      text-white font-medium text-sm\n                                      hover:shadow-lg transition-all duration-300\n                                      hover:scale-105`}>\n                      {feature.buttonText}\n                      <svg className=\"w-4 h-4 group-hover:translate-x-1 transition-transform\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\">\n                        <path strokeLinecap=\"round\" strokeLinejoin=\"round\" strokeWidth={2} d=\"M9 5l7 7-7 7\" />\n                      </svg>\n                    </button>\n                  )}\n                  \n                  {/* Decorative Corner */}\n                  <div className=\"absolute bottom-0 right-0 w-20 h-20 bg-gradient-to-tl from-white/5 to-transparent rounded-tl-3xl\"></div>\n                </div>\n              );\n            })}\n          </div>\n\n          {/* Call to Action */}\n          <div className=\"relative bg-gradient-to-r from-yellow-500/10 via-orange-500/10 to-red-500/10 rounded-2xl p-8 md:p-12 border border-white/10 backdrop-blur-sm\">\n            <div className=\"text-center\">\n              <h3 className=\"text-2xl md:text-3xl font-bold text-white mb-4\">\n                Ready to Start Your Journey?\n              </h3>\n              <p className=\"text-gray-300 mb-6 max-w-2xl mx-auto\">\n                Join thousands of successful students who have transformed their future through our scholarship programs.\n              </p>\n              <div className=\"flex flex-wrap gap-4 justify-center\">\n                <button className=\"px-6 py-3 bg-gradient-to-r from-yellow-500 to-orange-500 text-white font-semibold rounded-lg hover:shadow-xl transition-all duration-300 hover:scale-105\">\n                  Apply for Scholarship\n                </button>\n                <button className=\"px-6 py-3 border border-white/30 text-white font-semibold rounded-lg hover:bg-white/10 transition-all duration-300\">\n                  Contact Advisor\n                </button>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Custom Animations */}\n      <style jsx>{`\n        @keyframes float {\n          0%, 100% { transform: translateY(0px); }\n          50% { transform: translateY(-10px); }\n        }\n        .animate-float {\n          animation: float 3s ease-in-out infinite;\n        }\n      `}</style>\n    </>\n  );\n}"],"names":[],"mappings":";;;;;;AAAA;;;AAkBe,SAAS;IACtB,MAAM,WAAsB;QAC1B;YAAE,OAAO;YAAuB,MAAM;YAAM,OAAO;QAAO;QAC1D;YAAE,OAAO;YAA2B,MAAM;YAAM,OAAO;QAAQ;QAC/D;YAAE,OAAO;YAAyB,MAAM;YAAM,OAAO;QAAS;QAC9D;YAAE,OAAO;YAAsB,MAAM;YAAM,OAAO;QAAS;QAC3D;YAAE,OAAO;YAAoB,MAAM;YAAM,OAAO;QAAS;QACzD;YAAE,OAAO;YAAmB,MAAM;YAAM,OAAO;QAAM;QACrD;YAAE,OAAO;YAAuB,MAAM;YAAM,OAAO;QAAO;QAC1D;YAAE,OAAO;YAA0B,MAAM;YAAM,OAAO;QAAO;QAC7D;YAAE,OAAO;YAAiB,MAAM;YAAM,OAAO;QAAS;QACtD;YAAE,OAAO;YAAe,MAAM;YAAM,OAAO;QAAO;QAClD;YAAE,OAAO;YAAuB,MAAM;YAAO,OAAO;QAAU;QAC9D;YAAE,OAAO;YAAoC,MAAM;YAAM,OAAO;QAAO;KACxE;IAED,MAAM,sBAA4C;QAChD;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;QACA;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;QACA;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;QACA;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;QACA;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;QACA;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;QACA;YACE,OAAO;YACP,aAAa;YACb,MAAM;YACN,OAAO;YACP,YAAY;QACd;KACD;IAED,MAAM,kBAAkB,CAAC;QACvB,MAAM,SAAyG;YAC7G,MAAM;gBAAE,IAAI;gBAAkC,MAAM;gBAAiB,OAAO;gBAAsC,QAAQ;YAAkB;YAC5I,OAAO;gBAAE,IAAI;gBAAmC,MAAM;gBAAkB,OAAO;gBAAuC,QAAQ;YAAmB;YACjJ,QAAQ;gBAAE,IAAI;gBAAoC,MAAM;gBAAmB,OAAO;gBAAwC,QAAQ;YAAoB;YACtJ,QAAQ;gBAAE,IAAI;gBAAoC,MAAM;gBAAmB,OAAO;gBAAwC,QAAQ;YAAoB;YACtJ,QAAQ;gBAAE,IAAI;gBAAoC,MAAM;gBAAmB,OAAO;gBAAwC,QAAQ;YAAoB;YACtJ,KAAK;gBAAE,IAAI;gBAAiC,MAAM;gBAAgB,OAAO;gBAAqC,QAAQ;YAAiB;YACvI,MAAM;gBAAE,IAAI;gBAAkC,MAAM;gBAAiB,OAAO;gBAAsC,QAAQ;YAAkB;YAC5I,MAAM;gBAAE,IAAI;gBAAkC,MAAM;gBAAiB,OAAO;gBAAsC,QAAQ;YAAkB;YAC5I,QAAQ;gBAAE,IAAI;gBAAoC,MAAM;gBAAmB,OAAO;gBAAwC,QAAQ;YAAoB;YACtJ,MAAM;gBAAE,IAAI;gBAAkC,MAAM;gBAAiB,OAAO;gBAAsC,QAAQ;YAAkB;YAC5I,SAAS;gBAAE,IAAI;gBAAqC,MAAM;gBAAoB,OAAO;gBAAyC,QAAQ;YAAqB;YAC3J,QAAQ;gBAAE,IAAI;gBAAoC,MAAM;gBAAmB,OAAO;gBAAwC,QAAQ;YAAoB;YACtJ,MAAM;gBAAE,IAAI;gBAAkC,MAAM;gBAAiB,OAAO;gBAAsC,QAAQ;YAAkB;YAC5I,OAAO;gBAAE,IAAI;gBAAmC,MAAM;gBAAkB,